class Solution {
public:
    int numberOfArrays(string s, int k) {
        int n = s.size();
        vector<int> dp(n + 1, 0);
        dp[0] = 1;
        int mod = 1e9 + 7;
        for (int i = 1; i <= n; i++) {
            for (int j = i; j > 0 && j - 1 >= i - 10; j--) {
                string cur = s.substr(j - 1, i - j + 1);
                if (cur[0] == '0' || stoi(cur) > k) break;
                dp[i] = (dp[i] + dp[j - 1]) % mod;
            }
        }
        return dp[n];
    }
};

